parameters.jsCode:
// ────────────────────────────────────────────
// Prep T4 Search: หา CarePlan records ที่ Active
// และ Next_Due_Date ≤ TODAY + max alert days (14)
// ⚠️ Lark filter ไม่มี isOnOrBefore/isOnOrAfter — ใช้ isLessEqual/isGreaterEqual
// ⚠️ today + horizon ต้องใช้ Bangkok TZ (server UTC) — ไม่งั้น cron 07:00 BKK = 00:00 UTC วันเดิม
// ────────────────────────────────────────────
const token = $input.first().json.tenant_access_token;

// Bangkok-aware today (shift +7h then getUTC*)
function bkkDateStr(d) {
  const bkk = new Date(d.getTime() + 7 * 3600 * 1000);
  const yyyy = bkk.getUTCFullYear();
  const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
  const dd = String(bkk.getUTCDate()).padStart(2, '0');
  return yyyy + '-' + mm + '-' + dd;
}

const now = new Date();
const todayStr = bkkDateStr(now);
const horizonStr = bkkDateStr(new Date(now.getTime() + 14 * 86400000));

// Lark filter date value = ms timestamp (BKK midnight) — string YYYY-MM-DD ใช้ได้เฉพาะ text field
// Next Due Date เป็น Date field → ต้องส่ง ms
const horizonMs = new Date(horizonStr + 'T23:59:59+07:00').getTime();

// Lark filter — ไม่ใส่ filter เลย เพราะ Lark Date + Checkbox filter = 1254002 เสมอ
// ⚠️ ทุก filter condition (Date isLessEqual, Checkbox is) ทำให้ Lark ตอบ 1254002 silently
//    (HTTP 200 แต่ data=null) → n8n ไม่ error แต่ไม่ได้ข้อมูล
// Solution: fetch ALL T4 records แล้วกรองทั้งหมดใน Parse T4 Records (n8n-side)
//   - CP Status ≠ Done          → กรองใน Parse T4
//   - Active？ = true             → กรองใน Parse T4
//   - Auto Create Ticket？ = true → กรองใน Parse T4
//   - Next Due Date ≤ horizon    → กรองใน Parse T4 (withinAlert)
// T4 records ทั้งหมด ~200-500 rows → รับได้ใน 1 request (page_size: 500)
const searchBody = JSON.stringify({
  page_size: 500
  // ⚠️ ห้ามระบุ field_names — Lark จะไม่ return primary field ถ้า specify
});

return [{ json: { lark_token: token, searchBody, horizonStr, today: todayStr } }];

// ────────────────────────────────────────────
// Parse T4 records → flat array
// - Machine (Link→T2) / Customer (Link→T1): ใช้ extractLinkedRecord → record_id (group key)
// - Shop Name / Customer ID: 2-hop Lookup → Lark คืน plain text → txt() พอ
// ⚠️ Lark Date field = ms number (read) — ต้องใช้ dateStr() แปลง ไม่ใช่ txt().split('T')[0]
// ────────────────────────────────────────────
const res = $input.first().json;
const items = (res.data && res.data.items) || [];
const today = $('Prep Search T4').first().json.today;

function txt(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number') return String(v);
  if (v.text) return v.text;
  if (v.value !== undefined) {
    if (typeof v.value === 'string') return v.value;
    // { value: { text: "..." } } — Lookup nested object
    if (v.value && typeof v.value === 'object' && !Array.isArray(v.value)) {
      return v.value.text || v.value.name || v.value.value || '';
    }
    if (Array.isArray(v.value) && v.value.length > 0) {
      const f = v.value[0];
      return typeof f === 'string' ? f : (f.text || f.name || f.value || '');
    }
  }
  if (Array.isArray(v) && v[0]) {
    const f = v[0];
    return typeof f === 'string' ? f : (f.text || f.link || f.name || f.value || '');
  }
  return '';
}

function numVal(v) {
  if (v === null || v === undefined) return 0;
  if (typeof v === 'number') return v;
  const n = Number(txt(v));
  return isNaN(n) ? 0 : n;
}

// Lark Date field = Unix ms number. Convert to YYYY-MM-DD in Bangkok TZ.
// รองรับทั้ง number (ms) / string (YYYY-MM-DD หรือ YYYY/MM/DD)
// ⚠️ Formula Date field คืน { type: 5, value: [ms] } — ต้องแยก handle (พบ 2026-04-28)
function dateStr(v) {
  if (v === null || v === undefined || v === '') return '';
  // Formula field: { type: 5, value: [ms_number] }
  if (v && typeof v === 'object' && v.type === 5 && Array.isArray(v.value) && typeof v.value[0] === 'number') {
    v = v.value[0];
  }
  if (typeof v === 'number') {
    const bkk = new Date(v + 7 * 3600 * 1000);
    const yyyy = bkk.getUTCFullYear();
    const mm = String(bkk.getUTCMonth() + 1).padStart(2, '0');
    const dd = String(bkk.getUTCDate()).padStart(2, '0');
    return yyyy + '-' + mm + '-' + dd;
  }
  const s = typeof v === 'string' ? v : txt(v);
  if (!s) return '';
  return s.split('T')[0].replace(/\//g, '-');
}

// รองรับ 4 รูปแบบ response ของ linked field จาก Lark Base
//  1) [{ record_id, name }]
//  2) [{ record_ids, text }]   ← record_ids เป็น array
//  3) { value: [{ record_id, text }] }
//  4) { link_record_ids: ['rec...'] }  ← format จริงจาก T4.Machine (พบ 2026-04-28)
function extractLinkedRecord(v) {
  if (!v) return { record_id: '', display: '' };
  // Format 4: { link_record_ids: ['rec...'] }
  if (v.link_record_ids && Array.isArray(v.link_record_ids) && v.link_record_ids.length) {
    return { record_id: v.link_record_ids[0], display: '' };
  }
  const arr = Array.isArray(v) ? v : (Array.isArray(v.value) ? v.value : []);
  if (!arr.length) return { record_id: '', display: '' };
  const f = arr[0];
  if (typeof f === 'string') return { record_id: '', display: f };
  const rid = f.record_id || (Array.isArray(f.record_ids) ? f.record_ids[0] : f.record_ids) || '';
  const display = f.name || f.text || '';
  return { record_id: rid || '', display: display || '' };
}

const records = items.map(it => {
  const f = it.fields || {};
  const dueDate = dateStr(f['Next Due Date']);
  const stageNum = numVal(f['Stage Number']);

  // Lead Time priority: Lead Time Override (per-machine) > Alert Before (Days) (default) > stage-based fallback
  // เคส VIP อยากได้แจ้ง 21 วัน → admin ใส่ 21 ใน Lead Time Override field → cron ใช้ค่านั้น
  const leadOverride = numVal(f['Lead Time Override']);
  const alertBase = numVal(f['Alert Before (Days)']) || (stageNum <= 3 ? 7 : 14);
  const alertDays = leadOverride > 0 ? leadOverride : alertBase;

  // Linked fields → record_id เป็น group key
  const machine = extractLinkedRecord(f['Machine']);
  const customer = extractLinkedRecord(f['Customer']);
  // Assigned Technician (optional) → pre-fill ใน T5 ตอนสร้าง admin override ได้
  const assignedTech = extractLinkedRecord(f['Assigned Technician']);

  // 2-hop Lookup → Lark คืน plain text ผ่าน txt()
  const shopName = txt(f['Shop Name']);
  const customerIdText = txt(f['Customer ID']);
  // Machine code fallback: ดึงจาก Care Plan ID (format: CP-{CODE}-SN)
  const careIdRaw = txt(f['Care Plan ID']);
  const machineCodeFromId = (careIdRaw.match(/^CP-(.+)-S\d+$/) || [])[1] || '';

  // Check if within alert window: due_date - alert_days ≤ today
  const dueMs = new Date(dueDate + 'T00:00:00').getTime();
  const alertMs = dueMs - (alertDays * 86400000);
  const todayMs = new Date(today + 'T00:00:00').getTime();
  const withinAlert = todayMs >= alertMs;

  return {
    record_id: it.record_id,
    care_plan_id: txt(f['Care Plan ID']),
    machine_record_id: machine.record_id,          // ← group key (stable)
    machine_code: machine.display || machineCodeFromId, // T2 primary หรือ extract จาก Care Plan ID
    customer_record_id: customer.record_id,
    customer_id: customerIdText,                    // business key 'CUS-041' จาก Lookup
    shop_name: shopName,
    stage_number: stageNum,
    filter_name: txt(f['Filter Stage']) || txt(f['Service Item']),
    care_type: txt(f['Care Type']),
    next_due_date: dueDate,
    alert_before_days: alertDays,
    lead_override_used: leadOverride > 0,           // audit: ส่งต่อให้ Build T5 log ว่า override ทำงาน
    assigned_technician_id: assignedTech.record_id,  // '' ถ้ายังไม่ assign
    qty_per_visit: numVal(f['Qty per Visit']) || 1,
    within_alert: withinAlert,
    // n8n-side filters — ทั้งหมดเพราะ Lark API filter ไม่ reliable
    // Default = true ถ้า field ไม่มีใน response (record เก่าก่อน Path D = backward compatible)
    // Default = false ถ้า field มีแต่ถูก set เป็น false โดย admin
    cp_status: txt(f['CP Status']),
    active_flag: !('Active？' in f) ? true : (f['Active？'] === true || f['Active？'] === 1 || txt(f['Active？']) === 'true'),
    auto_create_flag: !('Auto Create Ticket？' in f) ? true : (f['Auto Create Ticket？'] === true || f['Auto Create Ticket？'] === 1 || txt(f['Auto Create Ticket？']) === 'true')
  };
}).filter(r => {
  if (!r.within_alert || !r.next_due_date || !r.machine_record_id) return false;
  // n8n-side filters (Lark API filter = unreliable → 1254002 on Date+Checkbox)
  if (r.cp_status === 'Done') return false;  // CP Status ≠ Done
  if (!r.active_flag) return false;           // Active？ = true only
  if (!r.auto_create_flag) return false;      // Auto Create Ticket？ = true only
  return true;
});

if (records.length === 0) {
  return [{ json: { has_records: false, count: 0, records: [] } }];
}

return [{ json: { has_records: true, count: records.length, records, lark_token: $('Prep Search T4').first().json.lark_token } }];

// ────────────────────────────────────────────
// Group by (Machine_ID, ISO_WEEK(due_date))
// เพื่อรวม stages ที่ due สัปดาห์เดียวกัน → 1 visit
// ────────────────────────────────────────────
const data = $input.first().json;
const records = data.records;
const lark_token = data.lark_token;

function getISOWeek(dateStr) {
  const d = new Date(dateStr + 'T00:00:00');
  d.setHours(0, 0, 0, 0);
  d.setDate(d.getDate() + 3 - ((d.getDay() + 6) % 7));
  const week1 = new Date(d.getFullYear(), 0, 4);
  return d.getFullYear() + '-W' + String(1 + Math.round(((d.getTime() - week1.getTime()) / 86400000 - 3 + ((week1.getDay() + 6) % 7)) / 7)).padStart(2, '0');
}

const groups = {};
for (const rec of records) {
  const weekKey = getISOWeek(rec.next_due_date);
  const key = rec.machine_record_id + '_' + weekKey;

  if (!groups[key]) {
    groups[key] = {
      machine_record_id: rec.machine_record_id,
      machine_code: rec.machine_code,
      customer_record_id: rec.customer_record_id,
      customer_id: rec.customer_id,
      shop_name: rec.shop_name,
      week_key: weekKey,
      stages: [],
      stage_names: [],
      stage_details: [],
      care_types: [],
      t4_record_ids: [],
      care_plan_ids: [],
      assigned_technician_id: '',       // first non-empty wins (all stages of same machine should share tech)
      total_qty_per_visit: 0,            // sum across stages → ช่างพกของรวม
      max_due_date: rec.next_due_date,
      max_lead_time: 0
    };
  }

  const g = groups[key];
  g.stages.push(rec.stage_number);
  g.stage_names.push('Stage ' + rec.stage_number + ' (' + rec.filter_name + ')');
  // checklist line: ☐ Stage N — FilterName [CareType] × Qty
  const qtyLabel = rec.qty_per_visit > 1 ? ' × ' + rec.qty_per_visit : '';
  g.stage_details.push('☐ Stage ' + rec.stage_number + ' — ' + rec.filter_name + ' [' + (rec.care_type || 'Service') + ']' + qtyLabel);
  if (rec.care_type && !g.care_types.includes(rec.care_type)) g.care_types.push(rec.care_type);
  g.t4_record_ids.push(rec.record_id);
  if (rec.care_plan_id && !g.care_plan_ids.includes(rec.care_plan_id)) {
    g.care_plan_ids.push(rec.care_plan_id);
  }
  if (!g.assigned_technician_id && rec.assigned_technician_id) {
    g.assigned_technician_id = rec.assigned_technician_id;
  }
  g.total_qty_per_visit += (rec.qty_per_visit || 1);
  if (rec.next_due_date > g.max_due_date) g.max_due_date = rec.next_due_date;

  // ใช้ alert_before_days จาก T4 (ไม่มี Interval field แยกในขั้นตอนนี้)
  const lt = rec.alert_before_days || (rec.stage_number <= 3 ? 7 : 14);
  if (lt > g.max_lead_time) g.max_lead_time = lt;
}

const groupList = Object.values(groups).sort((a, b) => a.max_due_date.localeCompare(b.max_due_date));

return [{ json: { groups: groupList, group_count: groupList.length, lark_token } }];

// ────────────────────────────────────────────
// Prep: Search T5 for existing open jobs
// เพื่อ idempotency check — ไม่สร้าง T5 ซ้ำ
// ⚠️ ห้ามระบุ field_names — Lark จะตัด primary field ทิ้ง
// ────────────────────────────────────────────
const data = $input.first().json;

// Query T5: Status NOT IN (เสร็จแล้ว, Cancelled) AND Source Ref ID = AUTO-CAREPLAN
const searchBody = JSON.stringify({
  filter: {
    conjunction: 'and',
    conditions: [
      { field_name: 'Source Ref ID', operator: 'is', value: ['AUTO-CAREPLAN'] },
      { field_name: 'Status', operator: 'isNot', value: ['เสร็จแล้ว'] },
      { field_name: 'Status', operator: 'isNot', value: ['Cancelled'] }
    ]
  },
  page_size: 500
});

return [{ json: { ...data, t5SearchBody: searchBody } }];

// ────────────────────────────────────────────
// Capacity Allocate (cp-011b)  — Phase 1
//
// Person-day budget allocation for today's planned jobs.
//
// Source of truth for cost model: [[sop/maintenance/pm-capacity-per-day]]
//
// Logic:
//   1) Compute cost per job from (job_type × machine_size)
//   2) Sort by priority (all-C):
//        1C = weighted overdue (10 pts/day overdue)
//        2C = filter > pm_small > pm_large (light first to clear backlog)
//        3C = customer_tier as tiebreaker (graceful: missing = 0)
//   3) Greedy fill DAILY_BUDGET → split jobs_today vs jobs_deferred
//   4) Deferred jobs are NOT created — cron tomorrow will retry
//      (overdue weighting will push them up if they keep getting deferred)
//
// V2 TODO: subtract today's already-existing T5 cost from budget
//          (currently assumes cron is sole creator; manual T5 ignored)
// ────────────────────────────────────────────

const data = $input.first().json;
const jobs = data.jobs || [];
const lark_token = data.lark_token;

// === CONFIG (edit ที่นี่ที่เดียวเมื่อ business เปลี่ยน) ===
const TOTAL_TECHS = 4;
const DAILY_BUDGET = TOTAL_TECHS * 1.0;  // 4.0 person-day

// PM เครื่องเล็ก: 73-127kg/วัน (ทำ 3 ร้าน/วัน/ช่าง — ต้องรอน้ำแข็ง)
const SMALL_MACHINES = ['SK-160P', 'SK-210P', 'SK-230P', 'SK-280P'];

// PM เครื่องใหญ่: ≥160kg/วัน — กิน 2 ช่าง × 1 วัน = 2.0 person-day budget
// SK-350P, SK-420P, SK-500P, SK-700P, SK-1000P, SK-1500P, SK-2000P

const COST = {
  filter:   0.12,   // 7-10 ร้าน/วัน/ช่าง — เบาสุด
  pm_small: 0.33,   // 3 ร้าน/วัน/ช่าง — รอน้ำแข็ง
  pm_large: 2.00,   // 2 ช่าง × 1 day — เครื่องใหญ่งานหนัก
  default:  0.30    // ไม่รู้ประเภท → ปานกลาง
};

function categorizeJob(job) {
  const stages = job.stages || [];
  const code = (job.machine_code || '').toUpperCase();
  const isSmall = SMALL_MACHINES.some(m => code.includes(m));

  // Filter-only visit = stages ทั้งหมดเป็นงานเบา (Stage 1, 3, 5)
  // Stage 2/4/6 = PM/ตะกรัน/RO → ของหนัก
  const filterOnly = stages.length > 0 && stages.every(s => [1, 3, 5].includes(s));
  if (filterOnly) return 'filter';

  return isSmall ? 'pm_small' : 'pm_large';
}

function jobCost(job) {
  return COST[categorizeJob(job)] ?? COST.default;
}

// === Priority sort (all-C) ===
const today = Date.now();

function dueMs(job) {
  return job.scheduled_date
    ? new Date(job.scheduled_date + 'T00:00:00+07:00').getTime()
    : today;
}

function overdueDays(job) {
  return Math.max(0, (today - dueMs(job)) / 86400000);
}

function priorityScore(job) {
  // Higher score = higher priority (สูงก่อน)
  // 1C: weighted overdue — ทุก 1 วันที่ overdue เพิ่ม 10 pts
  const overdueWeight = overdueDays(job) * 10;

  // 2C: filter > pm_small > pm_large  (เบาก่อน clear backlog)
  const cat = categorizeJob(job);
  const stageWeight = cat === 'filter' ? 5 : (cat === 'pm_small' ? 2 : 0);

  // 3C: customer tier as tiebreaker (graceful — ไม่มี field ก็ใช้งานได้)
  const tierWeight = ({ A: 3, B: 2, C: 1 }[job.customer_tier] || 0);

  // Tiebreaker: due date sooner ก่อน
  // (ใช้เป็น decimal เล็กๆ ไม่ overshadow weights ข้างบน)
  const dueProximity = -dueMs(job) / 1e13;

  return overdueWeight + stageWeight + tierWeight + dueProximity;
}

const sortedJobs = [...jobs].sort((a, b) => priorityScore(b) - priorityScore(a));

// === Greedy allocation under DAILY_BUDGET ===
const jobsToday = [];
const jobsDeferred = [];
let remaining = DAILY_BUDGET;

for (const job of sortedJobs) {
  const cost = jobCost(job);
  if (cost <= remaining + 1e-9) {
    jobsToday.push({ ...job, _cost: cost, _category: categorizeJob(job) });
    remaining -= cost;
  } else {
    jobsDeferred.push({ ...job, _cost: cost, _category: categorizeJob(job), _reason: 'over_capacity' });
  }
}

// === Output ===
// jobs (ที่ส่งต่อให้ Split Jobs) = jobsToday only
// jobs_deferred + capacity stats เก็บไว้สำหรับ Summary Log
return [{ json: {
  jobs: jobsToday,
  jobs_deferred: jobsDeferred,
  lark_token,
  has_new: jobsToday.length > 0,
  skipped: data.skipped || 0,
  capacity: {
    total_budget: DAILY_BUDGET,
    used: DAILY_BUDGET - remaining,
    remaining: remaining,
    today_count: jobsToday.length,
    deferred_count: jobsDeferred.length,
    by_category: {
      filter:   jobsToday.filter(j => j._category === 'filter').length,
      pm_small: jobsToday.filter(j => j._category === 'pm_small').length,
      pm_large: jobsToday.filter(j => j._category === 'pm_large').length
    }
  }
}}];

// ────────────────────────────────────────────
// Split: แตก jobs array → 1 item per job
// เพื่อให้ Loop node สร้าง T5 ทีละ record
// ────────────────────────────────────────────
const data = $input.first().json;
const jobs = data.jobs || [];
const lark_token = data.lark_token;

return jobs.map(job => ({ json: { ...job, lark_token } }));

// ────────────────────────────────────────────
// Build T5 record body for Lark Base create
// ⚠️ Per 2026-04-20 audit (fixed):
//   • T5.Customer is a LOOKUP field — resolved from Machine link, DO NOT write.
//   • T5.Machine is DuplexLink → T2 (writable). Write ["rec..."] NOT [{record_id}]
//   • T5.Related Care Plan is DuplexLink → T4 (writable; was 'T4 Refs' Text before).
//   • T5.Assigned Technician is Link → T8 (optional pre-fill from T4). Write ["rec..."]
//   • 'Status' SingleSelect option is 'รอยืนยัน'.
//   • 'Job Type' MultiSelect → must wrap ['CarePlan'] even for single value.
//   • 'Scheduled Date' = Date field → write เป็น ms timestamp ไม่ใช่ YYYY-MM-DD string
// ⚠️ Bug #7 pattern: ใช้ $input.all().map() ไม่ใช่ first()
//   Split Jobs ส่งมาหลาย items (1 item/job) — first() จะ drop job ที่ 2+ เงียบๆ
// ────────────────────────────────────────────

function toMs(dateStr) {
  if (!dateStr) return null;
  const d = new Date(dateStr + 'T00:00:00+07:00');
  return d.getTime();
}

return $input.all().map(item => {
  const job = item.json;

  const stagesText = job.stages.map(s => 'Stage ' + s).join(', ');
  // Checklist format for technician (human-readable, with checkboxes)
  const checklistText = (job.stage_details && job.stage_details.length > 0)
    ? job.stage_details.join('\n')
    : job.stage_names.join('\n');
  const idempotencyKey = 'CP_' + job.machine_record_id + '_' + job.week_key;

  const fields = {
    'Job No.': job.job_no,
    'Status': 'รอยืนยัน',
    'Stages Covered': job.stages.map(s => 'Stage ' + s),
    'Stage Details': checklistText,
    'Job Type': ['CarePlan'],
    // 'Total Qty': job.total_qty_per_visit, // ❌ field ไม่มีใน T5 schema
    'Scheduled Date': toMs(job.scheduled_date),
    'Source Ref ID': 'AUTO-CAREPLAN',
    'Idempotency Key': idempotencyKey
  };

  // Writable links — Lark Write format = ["rec..."] (array of ID strings)
  // 1) Machine (DuplexLink → T2) — always set (grouping key)
  // 2) Related Care Plan (DuplexLink → T4) — array of every T4 record in this visit
  // 3) Assigned Technician (Link → T8) — optional pre-fill; admin can override
  if (job.machine_record_id) {
    fields['Machine'] = [job.machine_record_id];
  }
  if (job.t4_record_ids && job.t4_record_ids.length > 0) {
    fields['Related Care Plan'] = job.t4_record_ids.slice();  // array of record_id strings
  }
  if (job.assigned_technician_id) {
    fields['Assigned Technician'] = [job.assigned_technician_id];
  }

  const body = JSON.stringify({ fields });

  return { json: { ...job, createBody: body } };
});

// ────────────────────────────────────────────
// Collect results: รวมผลลัพธ์จากทุก T5 ที่สร้าง
// + สร้าง LINE notification message
// ────────────────────────────────────────────
const allItems = $input.all();
const createdJobs = [];
const errors = [];

for (const item of allItems) {
  const d = item.json;
  // ตรวจว่า Lark ตอบ success
  if (d.data && d.data.record) {
    createdJobs.push({
      job_no: d.data.record.fields?.['Job No.'] || 'unknown',
      record_id: d.data.record.record_id,
      shop_name: d.data.record.fields?.['Shop Name'] || ''
    });
  } else if (d.code && d.code !== 0) {
    errors.push({ code: d.code, msg: d.msg || 'unknown error' });
  }
}

// Reconstruct from Split Jobs data for notification
const splitItems = $('Split Jobs').all();
const jobDetails = splitItems.map(si => si.json);

// Bangkok-aware today ในภาษาไทย + ค.ศ. (ไม่ใช้ toLocaleDateString('th-TH') เพราะ auto-แปลงเป็น พ.ศ.)
const TH_MONTHS_FULL = ['มกราคม','กุมภาพันธ์','มีนาคม','เมษายน','พฤษภาคม','มิถุนายน','กรกฎาคม','สิงหาคม','กันยายน','ตุลาคม','พฤศจิกายน','ธันวาคม'];
const TH_WEEKDAYS = ['อาทิตย์','จันทร์','อังคาร','พุธ','พฤหัสบดี','ศุกร์','เสาร์'];
const bkkNow = new Date(new Date().getTime() + 7 * 3600 * 1000);
const dateTH = 'วัน' + TH_WEEKDAYS[bkkNow.getUTCDay()] + 'ที่ ' + bkkNow.getUTCDate() + ' ' + TH_MONTHS_FULL[bkkNow.getUTCMonth()] + ' ' + bkkNow.getUTCFullYear();

let msg = '📋 SK-ICE CarePlan Alert\n';
msg += '📅 ' + dateTH + '\n\n';
msg += '🔧 มี ' + jobDetails.length + ' เครื่อง ใกล้ถึงกำหนด PM:\n\n';

jobDetails.forEach((job, i) => {
  const stageList = job.stages.sort((a,b) => a-b).join(', ');
  const displayName = job.shop_name || job.customer_id || job.machine_code || '(ไม่พบชื่อร้าน)';
  msg += (i + 1) + '. 🏪 ' + displayName + '\n';
  msg += '   Stage: ' + stageList + '\n';
  msg += '   📅 Due: ' + job.scheduled_date + '\n';
  msg += '   🏷️ ' + job.job_no + '\n\n';
});

if (errors.length > 0) {
  msg += '\n⚠️ Errors: ' + errors.length + ' records failed\n';
}

msg += '👉 เข้า Admin Dashboard เพื่อ confirm + assign ช่าง';

const skippedCount = $('Idempotency Filter1').first().json.skipped || 0;

return [{ json: {
  notification: msg,
  created_count: createdJobs.length,
  error_count: errors.length,
  skipped_count: skippedCount,
  lark_token: $('Idempotency Filter1').first().json.lark_token
} }];

