// ────────────────────────────────────────────
// Idempotency: Filter out groups ที่มี T5 open อยู่แล้ว
// Logic: อ่าน T5.Related Care Plan (DuplexLink → T4) ถ้า overlap กับ group.t4_record_ids → skip
// ⚠️ Fixed 2026-04-20: เดิมอ่าน 'T4 Refs' (field ไม่มีใน T5 schema) → refs='' เสมอ → ไม่ skip อะไรเลย → สร้าง T5 ซ้ำทุกวัน
//                     T5 schema จริงใช้ 'Related Care Plan' (DuplexLink) → ต้อง extract record_id[]
// ────────────────────────────────────────────
const prevData = $('Prep T5 Idempotency Search').first().json;
const groups = prevData.groups;
const lark_token = prevData.lark_token;

// Parse existing T5 records
const t5Res = $input.first().json;
const t5Items = (t5Res.data && t5Res.data.items) || [];

function txt(v) {
  if (v === null || v === undefined) return '';
  if (typeof v === 'string') return v;
  if (v.text) return v.text;
  if (Array.isArray(v)) return v.map(i => typeof i === 'string' ? i : (i.text || '')).join(',');
  return '';
}

// DuplexLink response format: [{ record_id, name/text }] หรือ { value: [...] }
function extractLinkedIds(v) {
  if (!v) return [];
  const arr = Array.isArray(v) ? v : (Array.isArray(v.value) ? v.value : []);
  return arr.map(r => {
    if (typeof r === 'string') return '';
    return r.record_id || (Array.isArray(r.record_ids) ? r.record_ids[0] : r.record_ids) || '';
  }).filter(Boolean);
}

const existingT5s = t5Items.map(it => {
  const f = it.fields || {};
  return {
    record_id: it.record_id,
    job_no: txt(f['Job No.']),
    status: txt(f['Status']),
    t4_refs: extractLinkedIds(f['Related Care Plan'])
  };
});

// Filter: keep groups that have NO overlap with existing open T5
const newGroups = groups.filter(group => {
  const hasOverlap = existingT5s.some(t5 => {
    return t5.t4_refs.some(ref => group.t4_record_ids.includes(ref));
  });
  return !hasOverlap;
});

const skipped = groups.length - newGroups.length;

if (newGroups.length === 0) {
  return [{ json: { has_new: false, new_count: 0, skipped, lark_token } }];
}

// Generate Job Numbers: CP-YYYY-MM-DD-NNN
const today = new Date().toISOString().split('T')[0];
const dated = today.replace(/-/g, '');
const jobsToCreate = newGroups.map((g, i) => {
  const seq = String(i + 1).padStart(3, '0');
  return {
    job_no: 'CP-' + dated + '-' + seq,
    machine_record_id: g.machine_record_id,   // ← stable T2 record_id for Link
    customer_record_id: g.customer_record_id, // pass-through (T5.Customer is Lookup)
    machine_code: g.machine_code,
    customer_id: g.customer_id,
    shop_name: g.shop_name,
    stages: g.stages.sort((a,b) => a-b),
    stage_names: g.stage_names,
    stage_details: g.stage_details || [],
    care_types: g.care_types || [],
    t4_record_ids: g.t4_record_ids,
    care_plan_ids: g.care_plan_ids,
    assigned_technician_id: g.assigned_technician_id || '',
    total_qty_per_visit: g.total_qty_per_visit || g.stages.length,
    scheduled_date: g.max_due_date,
    week_key: g.week_key
  };
});

return [{ json: { has_new: true, new_count: jobsToCreate.length, skipped, jobs: jobsToCreate, lark_token } }];

