  if (v.link_record_ids && Array.isArray(v.link_record_ids)) return v.link_record_ids;
  if (Array.isArray(v)) return v.map(x => (typeof x === 'object' && x.record_id) ? x.record_id : (typeof x === 'string' ? x : '')).filter(Boolean);
