// ────────────────────────────────────────────
// Generate Job No. : J-YYYYMMDD-XXX (sequence per day)
// 🎯 Owned in n8n (not Lark Formula) — vendor-portable.
// Trade-off: race condition possible if 2 requests come ms-apart.
//   Acceptable for admin dashboard (low concurrency).
// ────────────────────────────────────────────
const res = $input.first().json;
