    else if (v?.value && Array.isArray(v.value) && v.value[0]) s = v.value[0].text || v.value[0];
    return s;
  })
  .filter(s => s && s.startsWith(datePrefix))
  .map(s => parseInt(s.slice(datePrefix.length), 10))
  .filter(n => !isNaN(n));

const nextSeq = (seqs.length ? Math.max(...seqs) : 0) + 1;
const job_no = `${datePrefix}${String(nextSeq).padStart(3, '0')}`;

