for (const raw of rawPhones) {
  const digits = raw.replace(/\D/g, '');
  if (!/^0[6-9]/.test(digits)) continue; // Thai mobile only
  const intl = '66' + digits.slice(1);
  if (seen.has(intl)) continue;
  seen.add(intl);
  const msg = 'SK ICE: ประเมินงาน ' + src.job_id + ' ได้ที่: ' + shortUrl + ' ขอบคุณครับ 🙏';
  items.push({ json: { sms_recipient: intl, sms_msg: msg } });
}
return items;

const body = $input.first().json.body || $input.first().json;
const job_id        = body.job_id || '';
const comment       = body.comment || '';
const tech_names_all = body.tech_names || body.tech_name || '';
const customer_name = body.customer_name || '';
const timestamp     = new Date().toISOString().replace('T',' ').slice(0,19);

// Multi-tech mode: body.ratings = [{tech_name, rating}, ...]
if (body.ratings && Array.isArray(body.ratings) && body.ratings.length > 0) {
  return body.ratings.map(r => ({
    json: {
      timestamp,
      job_id,
      rating:        parseInt(r.rating) || 0,
      comment,
      tech_name:     r.tech_name || '',
      tech_names:    tech_names_all,
      customer_name
    }
  }));
}

// Single-tech mode
return [{ json: {
  timestamp,
  job_id,
  rating:        parseInt(body.rating) || 0,
  comment,
  tech_name:     body.tech_name || '',
  tech_names:    tech_names_all,
  customer_name
} }];
